#include <bits/stdc++.h>
using namespace std;
int n,sum,c[2][13],cp,a[13];
bool flag,use[13];
void dfs(int x,int rest){
    if(flag)
        return;
    if(x>n){
        if(rest==0){
            flag=true;
            for(int i=1;i<=n;i++)
                printf("%d ",a[i]);
        }
        return;
    }
    for(int i=1;i*c[cp][x]<=rest && i<=n && flag==false;i++)
        if(!use[i])
            use[i]=1,a[x]=i,dfs(x+1,rest-i*c[cp][x]),use[i]=0;
}
int main(){
    scanf("%d%d",&n,&sum);
    for(int i=1;i<=n;i++){
    	cp^=1;
        for(int j=1;j<=i;j++)
        	if(j==1 || j==i)
        		c[cp][j]=1;
        	else
            	c[cp][j]=c[cp^1][j-1]+c[cp^1][j];
    }
    dfs(1,sum);
    return 0;
}
